def process_payment(user: User, amount: Decimal, payment_method: Dict[str, Any]) -> PaymentResult:
    if amount <= 0:
        return PaymentResult(success=False, error="Payment amount must be greater than zero.")
    if not payment_method.get("token"):
        return PaymentResult(success=False, error="Missing payment token.")

    transaction_id = f"tx_{user.user_id}_{str(amount).replace('.', '_')}"
    return PaymentResult(success=True, transaction_id=transaction_id)


